import { useState } from "react";
import { useNavigate } from "react-router-dom";

function Home() {
    const [darkMode, setDarkMode] = useState(false);
    const navigate = useNavigate();

    const [courses, setCourses] = useState([]);


    const scholarshipData = {

        Government: [
            {
                title: "UPSC",
                amount: "50,000",
                marks: "75%",
                income: "Below 2 Lakh",
                duration: "12 Months",
                seats: "100"

            },

            {
                title: "SSC",
                amount: "40,000",
                marks: "70%",
                income: "Below 2 Lakh",
                duration: "10 Months",
                seats: "80"

            }
        ],

        Engineering: [
            {
                title: "B.Tech",
                amount: "80,000",
                marks: "80%",
                income: "Below 3 Lakh",
                duration: "4 years",
                seats: "120"
            },

            {
                title: "M.Tech",
                amount: "1,00,000",
                marks: "85%",
                income: "Below 4 Lakh",
                duration: "4 years",
                seats: "120"

            },
            {
                title: "Diploma",
                amount: "50,000",
                marks: "75%",
                income: "Below 2 Lakh",
                duration: "2 years",
                seats: "150"

            }
        ],

        Medical: [

            {
                title: "MBBS",
                amount: "1,00,000",
                marks: "85%",
                income: "Below 4 Lakh",
                duration: "5 Months",
                seats: "60"

            },
            {
                title: "Nursing",
                amount: "50,000",
                marks: "80%",
                income: "Below 4 Lakh",
                duration: "4 years",
                seats: "100"

            },
            {
                title: "Pharmacy",
                amount: "90,000",
                marks: "75%",
                income: "Below 3 Lakh",
                duration: "4 years",
                seats: "200"

            }
        ],

        Computer: [
            {
                title: "MCA",
                amount: "50,000",
                marks: "75%",
                income: "Below 3 Lakh",
                duration: "2 years",
                seats: "150"

            },
            {
                title: "BCA",
                amount: "30,000",
                marks: "75%",
                income: "Below 2 Lakh",
                duration: "3 years",
                seats: "150"

            },
            {
                title: "BSc CS",
                amount: "40,000",
                marks: "75%",
                income: "Below 5 Lakh",
                duration: "3 years",
                seats: "150"

            },
            {
                title: "BSc IT",
                amount: "40,000",
                marks: "75%",
                income: "Below 4 Lakh",
                duration: "3 years",
                seats: "200"

            }
        ]

    };


    const showCourses = (category) => {

        setCourses(scholarshipData[category]);

    }


    const applyCourse = (course) => {

        navigate("/apply", {
            state: { course }
        });

    }


    return (
        <div className= {darkMode ? "dark-container": "container"}>

            <h2>Scholarship Categories</h2>

            <button onClick={()=>setDarkMode(!darkMode)}>
                {
                    darkMode ? "Light Mode": "Dark Mode"
                }
            </button>
            <br/><br/>
            <div className="card-container">

                <div
                    className="card"
                    onClick={() => showCourses("Government")}
                >
                    Government
                </div>

                <div
                    className="card"
                    onClick={() => showCourses("Engineering")}
                >
                    Engineering
                </div>

                <div
                    className="card"
                    onClick={() => showCourses("Medical")}
                >
                    Medical
                </div>

                <div
                    className="card"
                    onClick={() => showCourses("Computer")}
                >
                    Computer
                </div>

            </div>


            <h3>Available Courses</h3>

            {

                courses.map((item, index) => (
                    <div className="scholarship-card" key={index}>
                        <h3>{item.title}</h3>
                        <p>Amount : {item.amount}</p>
                        <p>Minimum Marks: {item.marks}</p>
                        <p>Income Limit: {item.income}</p>
                        <p>Duration: {item.duration}</p>
                        <p>Seats Available: {item.seats}</p>

                        <button onClick={() => applyCourse(item.title)}>
                            Apply Now
                        </button>
                    </div>
                ))
            }
        </div>
    )
}
export default Home;
